import 'package:injectable/injectable.dart'; import '../../../core/utils/app_logger.dart'; @injectable class RingtoneService { bool _ringing = false; bool get isRinging => _ringing; Future<void> startRinging() async { _ringing = true; AppLogger.debug('Ringtone started'); } Future<void> stopRinging() async { _ringing = false; AppLogger.debug('Ringtone stopped'); } void dispose() => stopRinging(); }